import random
def orig(a,b):
    not_a = ~a & 0xffffffff
    xor = (not_a ^ b) & 0xffffffff
    # signed 32-bit comparison
    if xor >= 0x80000000:
        xor -= 0x100000000
    if not_a >= 0x80000000:
        not_a -= 0x100000000
    return xor < not_a
def new(a,b):
    xor = (a ^ b) & 0xffffffff
    a_s = a if a < 0x80000000 else a - 0x100000000
    xor_s = xor if xor < 0x80000000 else xor - 0x100000000
    return xor_s > a_s
for _ in range(10000):
    a = random.randint(0, 0xffffffff)
    b = random.randint(0, 0xffffffff)
    if orig(a,b) != new(a,b):
        print('mismatch', a, b, orig(a,b), new(a,b))
        break
else:
    print('all match')
""}

