def to_signed(v, bits=4):
    if v >= (1 << (bits-1)):
        return v - (1 << bits)
    return v
def test(bits=4):
    for x in range(1 << bits):
        for y in range(1 << bits):
            xor = x ^ y
            xs = to_signed(x, bits)
            xors = to_signed(xor, bits)
            if xors < xs:
                print(f'x={x:0{bits}b} y={y:0{bits}b} xor={xor:0{bits}b}')
                # maybe pattern depends on y?
    print('done')
test()
""}

