import random
def to_signed(v, bits=8):
    if v >= (1 << (bits-1)):
        return v - (1 << bits)
    return v
def test_pred(pred_name):
    pred_map = {'slt': lambda x,y: x < y,
                'sle': lambda x,y: x <= y,
                'sgt': lambda x,y: x > y,
                'sge': lambda x,y: x >= y,
                'eq': lambda x,y: x == y,
                'ne': lambda x,y: x != y}
    f = pred_map[pred_name]
    swapped_map = {'slt':'sgt','sle':'sge','sgt':'slt','sge':'sle','eq':'eq','ne':'ne'}
    swapped = swapped_map[pred_name]
    fsw = pred_map[swapped]
    bits=8
    for a in range(1<<bits):
        for b in range(1<<bits):
            not_a = (~a) & ((1<<bits)-1)
            xor1 = (not_a ^ b) & ((1<<bits)-1)
            a_s = to_signed(a,bits)
            not_a_s = to_signed(not_a,bits)
            xor1_s = to_signed(xor1,bits)
            res1 = f(xor1_s, not_a_s)
            xor2 = (a ^ b) & ((1<<bits)-1)
            xor2_s = to_signed(xor2,bits)
            res2 = fsw(xor2_s, a_s)
            if res1 != res2:
                print(f'FAIL {pred_name} a={a} b={b}')
                return False
    return True
for pred in ['slt','sle','sgt','sge','eq','ne']:
    if test_pred(pred):
        print(f'{pred} OK')
    else:
        print(f'{pred} FAIL')
EOF"}

