def to_unsigned(v, bits=8):
    return v & ((1<<bits)-1)
def test_pred(pred_name):
    pred_map = {'ult': lambda x,y: x < y,
                'ule': lambda x,y: x <= y,
                'ugt': lambda x,y: x > y,
                'uge': lambda x,y: x >= y}
    f = pred_map[pred_name]
    swapped_map = {'ult':'ugt','ule':'uge','ugt':'ult','uge':'ule'}
    swapped = swapped_map[pred_name]
    fsw = pred_map[swapped]
    bits=8
    for a in range(1<<bits):
        for b in range(1<<bits):
            not_a = (~a) & ((1<<bits)-1)
            xor1 = (not_a ^ b) & ((1<<bits)-1)
            res1 = f(xor1, not_a)
            xor2 = (a ^ b) & ((1<<bits)-1)
            res2 = fsw(xor2, a)
            if res1 != res2:
                print(f'FAIL {pred_name} a={a} b={b}')
                return False
    return True
for pred in ['ult','ule','ugt','uge']:
    if test_pred(pred):
        print(f'{pred} OK')
    else:
        print(f'{pred} FAIL')
EOF

